import { useState, useEffect } from "react";
import { useParams, Link } from "react-router-dom";
import axios from "axios";
import {
  ArrowLeft,
  MapPin,
  Clock,
  Mountain,
  TrendingUp,
  Loader2,
  ChevronRight,
  Images,
} from "lucide-react";
import { motion } from "framer-motion";
import { Header } from "../components/Header";
import { Footer } from "../components/Footer";
import { useLogoutHandler } from "../hooks/useLogoutHandler";
import LogoutModal from "../components/LogoutModal";

const API = "http://localhost:5000";

const difficultyColors = {
  Easy: "bg-emerald-100 text-emerald-700 border-emerald-200",
  Moderate: "bg-amber-100 text-amber-700 border-amber-200",
  Difficult: "bg-orange-100 text-orange-700 border-orange-200",
  Extreme: "bg-red-100 text-red-700 border-red-200",
};

/* ── Photo gallery grid layout for 1-5 images ── */
const PhotoGallery = ({ images }) => {
  if (!images?.length) return null;

  const count = Math.min(images.length, 5);
  const visible = images.slice(0, count);

  // Mosaic layouts
  if (count === 1) {
    return (
      <div className="w-full h-64 rounded-2xl overflow-hidden">
        <img
          src={`${API}${visible[0].image_path}`}
          alt="Trail photo"
          className="w-full h-full object-cover"
        />
      </div>
    );
  }

  if (count === 2) {
    return (
      <div className="grid grid-cols-2 gap-2 h-64 rounded-2xl overflow-hidden">
        {visible.map((img) => (
          <img
            key={img.image_id}
            src={`${API}${img.image_path}`}
            alt="Trail photo"
            className="w-full h-full object-cover"
          />
        ))}
      </div>
    );
  }

  if (count === 3) {
    // Classic tripod: left half + two stacked right
    return (
      <div className="grid grid-cols-2 gap-2 h-72 rounded-2xl overflow-hidden">
        <img
          src={`${API}${visible[0].image_path}`}
          alt="Trail photo"
          className="w-full h-full object-cover row-span-2"
        />
        <img
          src={`${API}${visible[1].image_path}`}
          alt="Trail photo"
          className="w-full h-full object-cover"
        />
        <img
          src={`${API}${visible[2].image_path}`}
          alt="Trail photo"
          className="w-full h-full object-cover"
        />
      </div>
    );
  }

  if (count === 4) {
    return (
      <div className="grid grid-cols-2 gap-2 rounded-2xl overflow-hidden">
        {visible.map((img) => (
          <div key={img.image_id} className="aspect-video overflow-hidden">
            <img
              src={`${API}${img.image_path}`}
              alt="Trail photo"
              className="w-full h-full object-cover"
            />
          </div>
        ))}
      </div>
    );
  }

  // 5 images: large left + 2x2 right
  return (
    <div className="grid grid-cols-2 gap-2 rounded-2xl overflow-hidden" style={{ height: "380px" }}>
      <img
        src={`${API}${visible[0].image_path}`}
        alt="Trail photo"
        className="w-full h-full object-cover"
      />
      <div className="grid grid-cols-2 gap-2">
        {visible.slice(1).map((img) => (
          <img
            key={img.image_id}
            src={`${API}${img.image_path}`}
            alt="Trail photo"
            className="w-full h-full object-cover"
          />
        ))}
      </div>
    </div>
  );
};

const TrailDetail = () => {
  const { id } = useParams();
  const [trail, setTrail] = useState(null);
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState(null);

  const {
    handleLogout: originalHandleLogout,
    handleStayLoggedIn,
    showLogoutModal,
    setShowLogoutModal,
  } = useLogoutHandler();

  const handleLogout = () => {
    originalHandleLogout();
  };

  useEffect(() => {
    const token = sessionStorage.getItem("token");
    const userData = sessionStorage.getItem("user");
    if (token && userData) setUser(JSON.parse(userData));
  }, []);

  useEffect(() => {
    const fetchTrail = async () => {
      try {
        const res = await axios.get(`${API}/api/trails/public/${id}`);
        setTrail(res.data.trail);
      } catch (err) {
        console.error("Error fetching trail:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchTrail();
  }, [id]);

  if (loading) {
    return (
      <div className="min-h-screen bg-cream flex items-center justify-center">
        <Loader2 className="h-10 w-10 animate-spin text-gold" />
      </div>
    );
  }

  if (!trail) {
    return (
      <div className="min-h-screen bg-cream flex flex-col items-center justify-center gap-4">
        <Mountain className="h-16 w-16 text-gray-300" />
        <h2 className="text-2xl font-bold text-charcoal">Trail Not Found</h2>
        <Link to="/" className="text-gold hover:text-gold-dark font-semibold flex items-center gap-1">
          <ArrowLeft className="h-4 w-4" /> Back to Home
        </Link>
      </div>
    );
  }

  const primaryImage = trail.images?.find((img) => img.is_primary);
  const heroImage = primaryImage
    ? `${API}${primaryImage.image_path}`
    : "https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=1200&q=80";

  const diff = difficultyColors[trail.difficulty_level] || difficultyColors["Moderate"];

  return (
    <div className="min-h-screen bg-cream">
      <Header user={user} onLogoutClick={() => setShowLogoutModal(true)} />

      {/* ── Hero Banner (primary image only, taller) ── */}
      <div className="relative h-[68vh] min-h-[540px] overflow-hidden">
        <img
          src={heroImage}
          alt={trail.trail_name}
          className="w-full h-full object-cover object-center"
        />

        {/* Multi-stop gradient: strong bottom, light top, keeps image visible in middle */}
        <div className="absolute inset-0"
          style={{ background: "linear-gradient(to top, rgba(0,0,0,0.82) 0%, rgba(0,0,0,0.35) 40%, rgba(0,0,0,0.08) 70%, rgba(0,0,0,0) 100%)" }}
        />

        {/* Back button */}
        <Link
          to="/"
          className="absolute top-24 left-6 inline-flex items-center gap-2 px-4 py-2 bg-black/30 backdrop-blur-md rounded-xl text-white text-sm font-medium border border-white/20 hover:bg-black/50 transition"
        >
          <ArrowLeft className="h-4 w-4" />
          Back to Trails
        </Link>

        {/* Title overlay */}
        <div className="absolute bottom-0 left-0 right-0 px-6 sm:px-10 pb-10">
          <div className="max-w-5xl mx-auto">
            {/* Difficulty badge */}
            <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold border bg-opacity-90 ${diff} mb-4`}>
              <TrendingUp className="h-3 w-3" />
              {trail.difficulty_level}
            </span>

            {/* Trail name */}
            <h1 className="text-3xl sm:text-4xl lg:text-5xl font-extrabold text-white mb-4 font-heading leading-tight drop-shadow-sm">
              {trail.trail_name}
            </h1>

            {/* Quick stats row */}
            <div className="flex flex-wrap items-center gap-x-5 gap-y-2">
              <span className="flex items-center gap-1.5 text-white/90 text-sm font-medium">
                <MapPin className="h-4 w-4 text-gold flex-shrink-0" />
                {trail.region}
              </span>
              <span className="flex items-center gap-1.5 text-white/90 text-sm font-medium">
                <Clock className="h-4 w-4 text-white/60 flex-shrink-0" />
                {trail.duration_days} {trail.duration_days === 1 ? "Day" : "Days"}
              </span>
              {trail.max_altitude && (
                <span className="flex items-center gap-1.5 text-white/90 text-sm font-medium">
                  <Mountain className="h-4 w-4 text-white/60 flex-shrink-0" />
                  {Number(trail.max_altitude).toLocaleString()}m altitude
                </span>
              )}
              {trail.images?.length > 0 && (
                <span className="flex items-center gap-1.5 text-white/60 text-sm">
                  <Images className="h-4 w-4 flex-shrink-0" />
                  {trail.images.length} photo{trail.images.length !== 1 ? "s" : ""}
                </span>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* ── Photo Gallery (tripod / mosaic) ── */}
      {trail.images?.length > 0 && (
        <div className="max-w-5xl mx-auto px-4 sm:px-6 mt-8">
          <div className="flex items-center gap-2 mb-4">
            <Images className="h-5 w-5 text-gold" />
            <h2 className="text-lg font-bold text-charcoal">Trail Photos</h2>
            <span className="text-xs text-gray-400 font-medium ml-1">
              ({Math.min(trail.images.length, 5)} of {trail.images.length})
            </span>
          </div>
          <PhotoGallery images={trail.images} />
        </div>
      )}

      {/* ── Main Content ── */}
      <div className="max-w-5xl mx-auto px-4 sm:px-6 py-12">
        <div className="grid lg:grid-cols-3 gap-10">

          {/* Left: Description + Itinerary */}
          <div className="lg:col-span-2 space-y-10">

            {/* Description */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.1 }}
            >
              <h2 className="text-2xl font-bold text-charcoal mb-4 font-heading">About This Trek</h2>
              <p className="text-gray-600 leading-relaxed whitespace-pre-line">{trail.description}</p>
            </motion.div>

            {/* Itinerary */}
            {trail.itineraries?.length > 0 && (
              <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.2 }}
              >
                <h2 className="text-2xl font-bold text-charcoal mb-6 font-heading">Day-by-Day Itinerary</h2>
                <div className="space-y-4">
                  {trail.itineraries.map((it) => (
                    <div
                      key={it.itinerary_id}
                      className="bg-white rounded-2xl p-5 border border-gray-100 shadow-sm hover:shadow-md transition-shadow"
                    >
                      <div className="flex items-center gap-3 mb-3">
                        <span className="inline-flex items-center justify-center w-10 h-10 rounded-xl bg-gold/10 text-gold font-extrabold text-sm flex-shrink-0">
                          {it.day_number}
                        </span>
                        <div>
                          <p className="text-xs text-gray-400 uppercase tracking-widest font-semibold">Day {it.day_number}</p>
                          {it.title && <p className="text-base font-bold text-charcoal">{it.title}</p>}
                        </div>
                      </div>
                      <p className="text-gray-600 text-sm leading-relaxed mb-3">{it.description}</p>
                      <div className="flex flex-wrap gap-4 text-xs text-gray-400">
                        {it.altitude && (
                          <span className="flex items-center gap-1">
                            <Mountain className="h-3.5 w-3.5 text-gold" />
                            {Number(it.altitude).toLocaleString()}m
                          </span>
                        )}
                        {it.distance_km && (
                          <span className="flex items-center gap-1">
                            <MapPin className="h-3.5 w-3.5" />
                            {it.distance_km} km
                          </span>
                        )}
                        {it.walking_hours && (
                          <span className="flex items-center gap-1">
                            <Clock className="h-3.5 w-3.5" />
                            {it.walking_hours} hrs walking
                          </span>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </motion.div>
            )}
          </div>

          {/* Right: Trek Details card */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
            className="lg:col-span-1"
          >
            <div className="bg-white rounded-2xl p-6 border border-gray-100 shadow-md sticky top-28 space-y-5">
              <h3 className="text-lg font-bold text-charcoal">Trek Details</h3>

              <div className="space-y-4">
                <div className="flex items-center justify-between py-3 border-b border-gray-100">
                  <span className="text-sm text-gray-500">Region</span>
                  <span className="text-sm font-semibold text-charcoal flex items-center gap-1">
                    <MapPin className="h-3.5 w-3.5 text-gold" />
                    {trail.region}
                  </span>
                </div>
                <div className="flex items-center justify-between py-3 border-b border-gray-100">
                  <span className="text-sm text-gray-500">Duration</span>
                  <span className="text-sm font-semibold text-charcoal">{trail.duration_days} Days</span>
                </div>
                <div className="flex items-center justify-between py-3 border-b border-gray-100">
                  <span className="text-sm text-gray-500">Difficulty</span>
                  <span className={`text-xs font-bold px-3 py-1 rounded-full border ${diff}`}>
                    {trail.difficulty_level}
                  </span>
                </div>
                {trail.max_altitude && (
                  <div className="flex items-center justify-between py-3 border-b border-gray-100">
                    <span className="text-sm text-gray-500">Max Altitude</span>
                    <span className="text-sm font-semibold text-charcoal">
                      {Number(trail.max_altitude).toLocaleString()}m
                    </span>
                  </div>
                )}
                {trail.images?.length > 0 && (
                  <div className="flex items-center justify-between py-3 border-b border-gray-100">
                    <span className="text-sm text-gray-500">Photos</span>
                    <span className="text-sm font-semibold text-charcoal">{trail.images.length}</span>
                  </div>
                )}
              </div>

              <Link
                to="/register"
                className="w-full inline-flex items-center justify-center gap-2 px-6 py-3.5 text-base font-bold text-navy rounded-xl shadow-lg shadow-gold/25 hover:shadow-xl hover:shadow-gold/40 hover:scale-[1.02] transition-all duration-300"
                style={{
                  background: "linear-gradient(135deg, #C8932A 0%, #E0B04A 100%)",
                }}
              >
                Book This Trek
                <ChevronRight className="h-5 w-5" />
              </Link>

              <p className="text-xs text-center text-gray-400">
                Free cancellation up to 48 hours before departure
              </p>
            </div>
          </motion.div>
        </div>
      </div>

      <Footer />

      <LogoutModal
        isOpen={showLogoutModal}
        onConfirm={handleLogout}
        onCancel={handleStayLoggedIn}
      />
    </div>
  );
};

export default TrailDetail;
